DO $$
BEGIN
  UPDATE products SET description = 'Areon Car Perfume Red - Design inspirador aliado a perfumes marcantes para um ambiente refrescante aonde quer que você vá. Aroma: Fragrância refrescante, que combina notas cítricas e amadeiradas. Família olfativa: Spicy. Notas de saída: lavanda, limão, pimenta. Notas de coração: violeta, jasmim. Notas de fundo: patchouli, vetiver, cedro, almíscar. Conteúdo: 01 odorizador de ambiente spray (50ml) e um difusor de celulose.', short_description = 'Areon Car Perfume Red - Design inspirador aliado a perfumes marcantes para um ambiente refrescante.', usability = '1- Retire o conteúdo da embalagem. 2- Pendure a celulose em seu veiculo, ou onde desejar, e retire a tampa do frasco. 3- Pulverizar duas ou três vezes dentro do carro ou sobre o cartão de celulose.', specifications = '{"Fragrância":"Refrescante, cítricas e amadeiradas","Família olfativa":"Spicy","Embalagem":"01 odorizador spray (50ml) e difusor de celulose","Notas de saída":"lavanda, limão, pimenta","Notas de coração":"violeta, jasmim","Notas de fundo":"patchouli, vetiver, cedro, almíscar"}'::jsonb WHERE id = 'ef150f64-201a-43eb-96ec-c2d30259a0e1';
  UPDATE products SET description = 'AREON CAR PERFUME VERANO AZUL - Todo charme e requinte em um aromatizante com notas exclusivas. Design agradável e aroma cuidadosamente selecionado, convida a sensação de frescor, pureza e conforto ao seu redor. Conteúdo: 01 odorizador de ambiente spray (50ml) e um difusor de celulose.', short_description = 'Odorizador Areon trará frescor duradouro e aroma agradável ao seu carro, casa, escritório e onde quiser.', usability = '1- Retire o conteúdo da embalagem. 2- Pendure a celulose em seu veiculo, ou onde desejar, e retire a tampa do frasco. 3- Pulverizar duas ou três vezes dentro do carro ou sobre o cartão de celulose.', specifications = '{"Embalagem":"01 odorizador spray (50ml) e difusor de celulose"}'::jsonb WHERE id = '45501fd9-9ca1-4dd3-a3ed-813d0267e94d';
  UPDATE products SET description = 'Areon Fresco Apple & Cinnamon (Maça e Canela) - A beleza e singularidade da natureza capturada neste pequeno dispensador de fragrâncias. Ótima propagação do perfume em seu carro. Perfeito para pequenos espaços. Perfume líquido em frascos de vidro. Receptáculo de madeira natural. Fragrância: Apple & Cinnamon. Notas de saída: Citrus, Especiarias. Notas principais: Frutado, Patchouli, Maçã, Aromático. Notas de base: Canela, Musk. Conteúdo: 01 odorizador líquido (4ml) e um difusor de madeira.', short_description = 'Perfume automotivo Areon Fresco com fragrância envolvente de maçã e canela. Design prático com pendurador para fácil uso.', specifications = '{"Fragrância":"Apple & Cinnamon","Embalagem":"01 odorizador líquido (4ml) e difusor de madeira","Notas de saída":"Citrus, Especiarias","Notas principais":"Frutado, Patchouli, Maçã, Aromático","Notas de base":"Canela, Musk"}'::jsonb WHERE id = '52902056-85fa-4e8d-ae16-bcef1fe83537';
  UPDATE products SET description = 'AREON FRESCO SPORT LUX GOLD - A beleza e singularidade da natureza capturada neste pequeno dispensador de fragrâncias. Ótima propagação do perfume em seu carro. Fragrância: Gold. Notas de base: Laranja, Limão, Pinheiros. Notas de Coração: Lavanda, Anis, Eucalipto, Rosa. Notas de base: Almíscar, Âmbar, Patchouli. Conteúdo: 01 odorizador líquido (4ml) e um difusor de madeira.', short_description = 'Perfume para carro Areon Fresco Sport Lux Gold com aroma fresco e sofisticado. Design elegante em madeira.', specifications = '{"Fragrância":"Gold","Embalagem":"01 odorizador líquido (4ml) e difusor de madeira","Notas de base":"Laranja, Limão, Pinheiros","Notas de coração":"Lavanda, Anis, Eucalipto, Rosa"}'::jsonb WHERE id = 'b031b2d5-b448-424d-a007-50138a0e9713';
  UPDATE products SET description = 'Black Magic é um tratamento para pneus que traz um novo conceito do conhecido "pretinho" para pneus. Diferentemente de outros produtos similares, Black Magic tem durabilidade de até 60 dias. Seu brilho é acetinado e seu resultado fica ainda melhor quando aplicado em pneus novos. Não deixa aspecto melado nem grudento. Após aplicação, cria uma camada repelente a água e a sujeira. Conteúdo: 150ml. Rendimento: até 40 pneus. Durabilidade: até 2 meses. Acompanha: Luva Plástica.', short_description = 'Black Magic Soft 99 tratamento super preto para pneus. Brilho seco e natural, longa durabilidade, hidrata a borracha.', usability = '1- Lavar e secar bem os pneus antes da aplicação. 2- Agite bem o produto e pressione levemente a esponja aplicadora sobre o pneu. 3- Aplique de maneira uniforme uma fina camada. 4- Deixe secar de 10 a 20 minutos. 5- Feche a tampa e guarde com a esponja virada para cima.', tips = 'Dica: Para um acabamento mais refinado, recomendamos a utilização da Esponja Tire Wax Soft99.', specifications = '{"Conteúdo":"150ml","Peso":"241 g","Rendimento":"até 40 pneus","Durabilidade":"até 2 meses","Acompanha":"Luva Plástica"}'::jsonb WHERE id = '5642642c-2b40-4a9a-b836-b330a51b4b08';
END $$;